scwin.f_RetrievePierCd = async function (param1, param2) {
  dma_co_ds_combo1.set("sysCd", "DailyStevedoringWorkIndicationEBC");
  dma_co_ds_combo1.set("queryId", "retrieveWorkPlanListCombo");
  dma_co_ds_combo1.set("param1", param1);
  dma_co_ds_combo1.set("param2", param2);

  //submit 처리.
  let objSubmit = await $c.sbm.execute($p, sbm_co_ds_combo1);
  if (objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {
    await scwin.sbm_co_ds_combo1_submitdone();
  }
};

//for=co_ds_combo1 event=OnLoadCompleted
scwin.sbm_co_ds_combo1_submitdone = async function (e) {
  ds_co_ds_combo1.sort("code", 0);
  if (ds_co_ds_combo1.getRowCount() > 0) {
    $c.gus.cfEnableObj($p, acb_wrkIndictNo, true);
    $c.gus.cfEnableObj($p, btn_no1, true);
  } else {
    $c.gus.cfEnableObj($p, acb_wrkIndictNo, false);
    $c.gus.cfEnableObj($p, btn_no1, false);
  }
  if (scwin.parentObj.ds_main2.getRowCount() > 0) {
    if (scwin.parentObj.ds_main2.getCellData(0, "completeProcYn") == "1") {
      $c.gus.cfEnableObj($p, btn_no1, false);
    } else {
      $c.gus.cfEnableObj($p, btn_no1, true);
    }
  }
  if (ds_main6.getRowCount() > 0) {
    ds_main6.reform();
  }
  if (ds_main7.getRowCount() > 0) {
    ds_main7.reform();
  }
  if (ds_main8.getRowCount() > 0) {
    ds_main8.reform();
  }
};

