//필요규격 item 필터링 처리위한 로직추가.
//필요규격 셀 클릭하여 수정하기전 필터반영처리.
//셀값 수정(item 선택전) 혹은 셀클릭 이후는 afteredit 에서 필터 clear 처리필요.
scwin.gr_main6_onbeforeedit = function (rowIndex, columnIndex, value) {
  //필요규격 item 필터링 처리.
  if (columnIndex == 9) {
    var sFillterStr = ds_main6.getCellData(rowIndex, "eqKndCd");
    var fn_colFilter = function (cellData, tmpParam, rowIdx) {
      if (cellData == sFillterStr) {
        return true;
      }
      return false; // return이 true인 경우 적용하고 false인 경우 넘김
    };
    ds_LkStepNo2.setColumnFilter({
      type: 'func',
      colIndex: 'upperCd',
      key: fn_colFilter,
      condition: 'and'
    });
    ds_LkStepNo2.insertRow(0);
    ds_LkStepNo2.setCellData(0, "name", "");
    ds_LkStepNo2.setCellData(0, "code", "");
    ds_LkStepNo2.reform();
  }
};

//for=gr_main6 event=OnExit 처리위한 로직2.(별도 함수 호출위한 로직)
//그리드 cell focus out 처리(상기 로직1의 변경되기전 정보가 없는 경우도 호출함.)
scwin.gr_main6_onafteredit = async function (rowIndex, columnIndex, value) {
  //필요규격 item 필터링 이후 타 row 의 필요규격 값 영향도 존재하므로 clear 처리.
  if (columnIndex == 9) {
    ds_LkStepNo2.clearFilter();
  }
  if (scwin.gr_main6_beforeCellChgInfos != undefined && scwin.gr_main6_beforeCellChgInfos != null && scwin.gr_main6_beforeCellChgInfos != "" && Object.keys(scwin.gr_main6_beforeCellChgInfos).length > 0) {
    var cellRow = scwin.gr_main6_beforeCellChgInfos.rowIndex;
    var cellID = scwin.gr_main6_beforeCellChgInfos.colID;
    var cellOldVal = scwin.gr_main6_beforeCellChgInfos.oldValue;
    if (rowIndex == cellRow && gr_main6.getColumnID(columnIndex) == cellID) {
      await scwin.gr_main6_OnExit(cellRow, cellID, cellOldVal);
    }
  }
  if ("자사" == ds_main6.getCellData(rowIndex, "clntNm")) {
    gr_main6.setReadOnly("cell", rowIndex, "clntNm", true);
    gr_main6.setReadOnly("cell", rowIndex, "clntNo", true);
    scwin.f_defaultCall(); // Key 값 수정 X
  } else {
    gr_main6.setReadOnly("cell", rowIndex, "clntNm", false);
    gr_main6.setReadOnly("cell", rowIndex, "clntNo", false);
    scwin.f_defaultCall(); // Key 값 수정 X
  }
};
